import redis
import sys

class AdvancedCacheClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, lua_script, num_keys=0, *args):
        try:
            result = self.redis_client.eval(lua_script, num_keys, *args)
            return result
        except redis.exceptions.RedisError as e:
            print(f"Redis error: {e}")
            return None
        except Exception as e:
            print(f"Error executing Lua script: {e}")
            return None
    
    def get_cache_data(self, key):
        lua_script = """
        local value = redis.call('GET', KEYS[1])
        if value then
            return {1, value}
        else
            return {0, nil}
        end
        """
        result = self.execute_lua_script(lua_script, 1, key)
        return result[1] if result and result[0] == 1 else None
    
    def set_cache_data(self, key, value, expire_seconds=0):
        lua_script = """
        local result = redis.call('SET', KEYS[1], ARGV[1])
        if ARGV[2] ~= '0' then
            redis.call('EXPIRE', KEYS[1], ARGV[2])
        end
        return result
        """
        return self.execute_lua_script(lua_script, 1, key, value, str(expire_seconds))
    
    def update_cache_with_ttl(self, key, value, ttl_seconds):
        lua_script = """
        local current_value = redis.call('GET', KEYS[1])
        if current_value then
            redis.call('SET', KEYS[1], ARGV[1])
            redis.call('EXPIRE', KEYS[1], ARGV[2])
            return 1
        else
            return 0
        end
        """
        return self.execute_lua_script(lua_script, 1, key, value, str(ttl_seconds))
    
    def batch_cache_operations(self, operations):
        lua_script = """
        local results = {}
        for i = 1, #KEYS do
            if ARGV[i] == 'SET' then
                redis.call('SET', KEYS[i], ARGV[#KEYS + i])
                table.insert(results, 'OK')
            elseif ARGV[i] == 'GET' then
                local value = redis.call('GET', KEYS[i])
                table.insert(results, value or '')
            elseif ARGV[i] == 'DEL' then
                local deleted = redis.call('DEL', KEYS[i])
                table.insert(results, deleted)
            end
        end
        return results
        """
        keys = [op['key'] for op in operations]
        commands = [op['command'] for op in operations]
        values = [op.get('value', '') for op in operations]
        
        args = commands + values
        return self.execute_lua_script(lua_script, len(keys), *keys, *args)

